const input = $input.first()?.json.body || $input.first()?.json || {};
const provider_id = input.provider_id !== undefined ? Number(input.provider_id) : null;
const service_id = input.service_id !== undefined ? Number(input.service_id) : null;
const title = input.title !== undefined ? String(input.title).trim() : '';
const content = input.content !== undefined ? String(input.content).trim() : '';
const language = input.language !== undefined ? String(input.language).toLowerCase().trim() : 'es';
const status = input.status !== undefined ? String(input.status).toLowerCase().trim() : 'published';
const summary = input.summary !== undefined ? String(input.summary).trim() : '';
const source_type = input.source_type !== undefined ? String(input.source_type).toLowerCase().trim() : 'other';
let metadata = input.metadata || {};
const errors = [];
const validStatuses = ['draft', 'published', 'archived'];
const validSources = ['faq', 'policy', 'service', 'emergency', 'other'];

function ve(msg) {
  return [{ json: {
    success: false, error_code: 'VALIDATION_ERROR', error_message: msg, data: null,
    _meta: { source: 'RAG_01_Document_Ingestion', timestamp: new Date().toISOString() },
    _exit_early: true
  }}];
}

if (!Number.isInteger(provider_id) || provider_id <= 0) errors.push('provider_id must be positive integer');
if (title.length < 5 || title.length > 200) errors.push('title must be 5-200 chars');
if (content.length < 10 || content.length > 50000) errors.push('content must be 10-50000 chars');
if (!validStatuses.includes(status)) errors.push('status must be: draft, published, archived');
if (!validSources.includes(source_type)) metadata.original_source_type = source_type;
if (language.length !== 2) errors.push('language must be 2 chars');

if (errors.length > 0) return ve(errors.join(' | '));

return [{ json: { 
  provider_id, service_id: service_id || null, 
  title: title.substring(0, 500), content: content.substring(0, 50000), 
  summary: summary.substring(0, 1000), 
  source_type: validSources.includes(source_type) ? source_type : 'other', 
  status, language, metadata, _validated: true 
} }];

const input = $input.first().json;
const isValid = input._validated === true;
return [{ json: { ...input, _route: isValid ? 'execute' : 'error' } }];

// Gate Valid Skip: pass validation errors to output
const input = $input.first().json;
if (input.success === true) return [];
return [{ json: input }];

const response = $input.first()?.json;
const validatedData = $('Validate & Normalize').first()?.json || {};

function ve(msg) {
  return [{ json: {
    success: false, error_code: 'EMBEDDING_ERROR', error_message: msg, data: null,
    _meta: { source: 'RAG_01_Document_Ingestion', timestamp: new Date().toISOString() },
    _exit_early: true
  }}];
}

if (!response || !response.data || !Array.isArray(response.data) || response.data.length === 0) {
  return ve('OpenAI returned empty or invalid response');
}

const embedding = response.data[0]?.embedding;
if (!Array.isArray(embedding) || embedding.length !== 1536) {
  return ve('Expected 1536 floats, got length ' + (embedding?.length ?? 'undefined'));
}
if (!embedding.every(n => typeof n === 'number' && isFinite(n))) {
  return ve('Embedding contains non-finite values');
}

return [{ json: { ...validatedData, embedding, _embedded: true } }];

const input = $input.first().json;
const isOk = input._embedded === true && !input._exit_early;
return [{ json: { ...input, _route: isOk ? 'execute' : 'error' } }];

// Gate Embedding Error
const input = $input.first().json;
if (input.embedding && input.embedding.length === 1536) return [];
return [{ json: input }];

const d = $input.first()?.json;

function ve(msg) {
  return [{ json: {
    success: false, error_code: 'BUILD_ERROR', error_message: msg, data: null,
    _meta: { source: 'RAG_01_Document_Ingestion', timestamp: new Date().toISOString() },
    _exit_early: true
  }}];
}

if (!Array.isArray(d.embedding) || d.embedding.length !== 1536) return ve('invalid embedding');
if (!Number.isInteger(d.provider_id) || d.provider_id <= 0) return ve('invalid provider_id');
if (!d.title || d.title.length < 5) return ve('invalid title');
if (!d.content || d.content.length < 10) return ve('invalid content');

const esc = (s, maxLen = 500) => String(s ?? '')
  .replace(/\\/g, '\\\\')
  .replace(/'/g, "''")
  .substring(0, maxLen);

const embeddingLiteral = `'[${d.embedding.join(',')}]'::vector(1536)`;
const serviceIdLiteral = (d.service_id !== null && Number.isInteger(d.service_id))
  ? String(d.service_id)
  : 'NULL';

let metaJson;
try {
  metaJson = JSON.stringify(d.metadata || {});
  if (metaJson.length > 10000) return ve('metadata too large');
} catch(e) {
  return ve('metadata serialization failed');
}

const query = `
INSERT INTO rag_documents (
  provider_id, service_id, title, content, summary, embedding, source_type, status, language, metadata
) VALUES (
  ${d.provider_id}::bigint,
  ${serviceIdLiteral}${serviceIdLiteral !== 'NULL' ? '::bigint' : ''},
  '${esc(d.title)}'::text,
  '${esc(d.content, 50000)}'::text,
  '${esc(d.summary)}'::text,
  ${embeddingLiteral},
  '${esc(d.source_type)}'::rag_source_type,
  '${esc(d.status)}'::rag_document_status,
  '${esc(d.language, 10)}'::text,
  '${esc(metaJson, 10000)}'::jsonb
)
RETURNING id, provider_id, title, created_at;
`.trim();

const archive_query = `
UPDATE rag_documents
SET status = 'archived', deleted_at = NOW()
WHERE provider_id = ${d.provider_id}::bigint
  AND title = '${esc(d.title)}'::text
  AND source_type = '${esc(d.source_type)}'::rag_source_type
  AND status = 'published'
RETURNING id;
`.trim();

return [{ json: { query, archive_query, provider_id: d.provider_id, _built: true } }];

const rows = $input.all();
function ve(msg) {
  return [{ json: {
    success: false, error_code: 'DATABASE_ERROR', error_message: msg, data: null,
    _meta: { source: 'RAG_01_Document_Ingestion', timestamp: new Date().toISOString() },
    _exit_early: true
  }}];
}
if (!rows || rows.length === 0) return ve('INSERT returned no rows');
const row = rows[0]?.json;
if (!row || row.id === undefined || row.id === null) return ve('INSERT succeeded but returned no id');
return [{ json: { db_row: row, _inserted: true } }];

const input = $input.first().json;
const isOk = input._inserted === true && !input._exit_early;
return [{ json: { ...input, _route: isOk ? 'execute' : 'error' } }];

// Gate Insert Error
const input = $input.first().json;
if (input.db_row && input.db_row.id) return [];
return [{ json: input }];

// Format Success Response - Standard Contract O02
const dbRow         = $input.first()?.json?.db_row || {};
const validatedData = $('Validate & Normalize').first()?.json || {};

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      document_id: dbRow.id,
      title:       dbRow.title       || validatedData.title,
      provider_id: dbRow.provider_id || validatedData.provider_id,
      created_at:  dbRow.created_at  || new Date().toISOString()
    },
    _meta: {
      source:      'RAG_01_Document_Ingestion',
      timestamp:   new Date().toISOString(),
      workflow_id: $workflow.id,
      version:     '1.7.0'
    }
  }
}];

// Central Error Handler - Standard Contract O02
const input = $input.first()?.json || {};
let errorCode    = input.error_code    || 'GENERAL_ERROR';
let errorMessage = input.error_message || input.message || 'Unknown error occurred';

return [{
  json: {
    success:       false,
    error_code:    errorCode,
    error_message: errorMessage,
    data:          null,
    _meta: {
      source:      'RAG_01_Document_Ingestion',
      timestamp:   new Date().toISOString(),
      workflow_id: $workflow.id,
      version:     '1.7.0'
    }
  }
}];

const rows = $input.all();
const buildData = $('Build Parameterized Query').first()?.json;
if (!buildData || !buildData.query) {
  return [{ json: {
    success: false, error_code: 'ARCHIVE_ERROR', error_message: 'Build data not found', data: null,
    _meta: { source: 'RAG_01_Document_Ingestion', timestamp: new Date().toISOString() },
    _exit_early: true
  }}];
}
return [{ json: { ...buildData, archived_count: rows.length } }];

// 📤 STANDARD CONTRACT OUTPUT (O02)
const result = $input.first()?.json || {};
return [{
  json: {
    success: result.success !== false,
    error_code: result.success === false ? (result.error_code || 'UNKNOWN_ERROR') : null,
    error_message: result.success === false ? (result.error_message || 'An error occurred') : null,
    data: result.data || null,
    _meta: {
      source: 'RAG_01_DOCUMENT_INGESTION',
      workflow_id: $workflow.id,
      timestamp: new Date().toISOString(),
      version: '1.7.0'
    }
  }
}];

const input = $input.first().json;
if (input._route !== 'execute') return [];
return [{ json: input }];

const input = $input.first().json;
if (input._route === 'execute') return [];
return [{ json: input }];

